class PersistentWeightSegmemtTree {
private:
	struct tree { 
		int l = 0, r = 0; 
		ll cnt = 0, sum = 0;
	}; // 树上的节点
	int tot = 0;    // 记录节点个数，并作为版本编号
	vector<tree>t;  // 存树各个的节点 
	int len;        // 离散化后的数的个数，也是值域大小 (可不开离散化，纯靠动态开点即可)

	int build(int l, int r) {
		int node = ++tot;
		if (l == r)return node;
		int mid = l + r >> 1;
		t[node].l = build(l, mid);
		t[node].r = build(mid + 1, r);
		return node;
	}
public:
	vector<int>root; // 存各个版本线段树的根节点编号

	PersistentWeightSegmemtTree(int len, int n, bool f = 1) :len(len), t((n << 5) + 10), root(n + 10) {
		/**
		* len：值域大小，不用 +1 (值域可以非常大，只要不建初始化空树即可(f=0))
		* n：原始数组长度，不用 +1
		* f：值域是否较小(<= 1e6)。若值域过大，且决定不用离散化，不能建空树，纯靠动态开点。除了 f=0，别的地方写法不变
		*/
		if (f)root[0] = build(1, len);
	}

	int update(int l, int r, int pos, ll value, int pre) {
		int node = ++tot;     // 开新节点
		t[node] = t[pre];     // 复制上个版本的左右子树指针
		t[node].cnt += value; // 原有的值上 += value
		t[node].sum += pos * value;

		if (l == r)return node;

		int mid = l + r >> 1;
		if (pos <= mid)  // 要修改的 pos 在左子，左子需要开新的节点，右子不变 (继承 pre)
			t[node].l = update(l, mid, pos, value, t[pre].l);
		else             // 同理
			t[node].r = update(mid + 1, r, pos, value, t[pre].r);
		return node;
	}

	int update(int pos, int value, int pre) {
		return update(1, len, pos, value, pre);
	}

	ll query(int L, int R, int k) {
		var query = [&](var query, int u, int v, int l, int r, ll k)->ll {
			if (l == r) {
				ll cnt = t[v].cnt - t[u].cnt;
				return l * min(cnt, k);
			}

			int mid = l + r >> 1;

			// rnum 为值域下标区间 [mid + 1, r] 中数的个数
			int rnum = t[t[v].r].cnt - t[t[u].r].cnt;

			if (k <= rnum) // 第 k 大在右子
				return query(query, t[u].r, t[v].r, mid + 1, r, k); // 往右区间 [mid + 1, r] 找
			else { // 第 k 大在左子，右子全拿下
				ll sum = t[t[v].r].sum - t[t[u].r].sum;
				return query(query, t[u].l, t[v].l, l, mid, k - rnum) + sum; // 往左区间 [l, mid] 找
			}
			};

		return query(query, root[L], root[R], 1, len, k);
	}

};


ll pre[N];
void init() {
	// 初始化 1^2 + 2^2 + 3^2 + ... + n^2
	fa(i, 1, 1e5)pre[i] = pre[i - 1] + i * 1ll * i;
}
void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];

	PersistentWeightSegmemtTree sg(1e6, n, 0);
	fa(i, 1, n)sg.root[i] = sg.update(a[i], 1, sg.root[i - 1]);

	int q; cin >> q;
	while (q--) {
		int l, r, k; cin >> l >> r >> k;
		int len = r - l + 1;
		ll ans = pre[len] + sg.query(l - 1, r, k);
		cout << ans << endl;
	}
	return;
}
